class Solution:
    def maxBalancedShipments(self, weight):
        n = len(weight)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(maxsize=None)
        def best(start):
            if start >= n:
                return 0
            res = best(start + 1)
            mx = weight[start]
            for end in range(start + 1, n):
                mx = max(mx, weight[end])
                if weight[end] < mx:
                    res = max(res, 1 + best(end + 1))
            return res
        return best(0)

