class Solution:
    def maxBalancedShipments(self, weight):
        count = 0
        cur_max = -1
        for w in weight:
            if cur_max == -1:
                cur_max = w
            elif w < cur_max:
                count += 1
                cur_max = -1
            else:
                cur_max = w
        return count

